const express = require('express');
const app = express();
const bodyParser = require('body-parser');

app.use(bodyParser.json());

let plugins = [];

function loadPlugins() {
  const config = require('./config');
  if (config.plugins) {
    config.plugins.forEach(plugin => {
      try {
        let pluginCode;
        if (plugin.type === 'eval') {
          pluginCode = eval(plugin.code);
        } else if (plugin.type === 'require') {
          pluginCode = require(plugin.code);
        }
        plugins.push(pluginCode);
      } catch (err) {
        console.error(`Error loading plugin: ${err}`);
      }
    });
  }

  const envPlugins = process.env.PLUGINS;
  if (envPlugins) {
    try {
      let pluginCode;
      if (envPlugins.startsWith('eval:')) {
        pluginCode = eval(envPlugins.slice(5));
      } else if (envPlugins.startsWith('require:')) {
        pluginCode = require(envPlugins.slice(8));
      }
      plugins.push(pluginCode);
    } catch (err) {
      console.error(`Error loading plugin from env: ${err}`);
    }
  }

  app.use((req, res, next) => {
    plugins.forEach(plugin => {
      if (plugin.beforeRequest) {
        plugin.beforeRequest(req, res, next);
      }
    });
    next();
  });

  app.use((req, res, next) => {
    plugins.forEach(plugin => {
      if (plugin.afterRequest) {
        plugin.afterRequest(req, res, next);
      }
    });
    next();
  });

  app.use((req, res, next) => {
    plugins.forEach(plugin => {
      if (plugin.onResponse) {
        plugin.onResponse(req, res, next);
      }
    });
    next();
  });
}

loadPlugins();

app.get('/api', (req, res) => {
  res.json({ message: 'Hello from API Gateway' });
});

const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`API Gateway listening on port ${port}`);
});